default.user_stylesheet:
body {
    max-inline-size: 65ch !important;
    margin-inline: auto !important;
    font-size: clamp(20px, 1.4vw, 24px) !important;
    font-family: "New York", Charter, Georgia, "Hiragino Mincho ProN", "Yu Mincho", serif !important;
    line-height: 1.7 !important;
    -webkit-font-smoothing: antialiased;
    text-wrap: pretty;
    hyphens: auto;
}

h1, h2, h3, h4 {
    font-family: system-ui, "Hiragino Sans", "Yu Gothic", sans-serif;
    line-height: 1.25 !important;
    margin-block: 2.5rem 1rem !important;
}

p, ul, ol, blockquote, pre {
    margin-block: 0 1.25em !important;
}

a { color: inherit; text-underline-offset: 3px; }

img {
    max-inline-size: 100% !important;
    block-size: auto !important;
    display: block;
    margin-block: 2rem;
    margin-inline: auto;
}

blockquote {
    border-inline-start: 2px solid;
    padding-inline-start: 1rem;
    font-style: italic;
}
